"use strict";
import Swiper from "swiper";
import { Navigation } from "swiper/modules";

export default function () {
    document.addEventListener("DOMContentLoaded", () => {
        const initSlider = document.querySelector(".o-home-hero__cards");
        if (!initSlider) return;

        const swiper = new Swiper(".o-home-hero__cards", {
            modules: [Navigation],
            slidesPerView: 1,
            spaceBetween: 16,
            loop: true,
            navigation: {
                nextEl: ".o-home-hero__arrow--next",
                prevEl: ".o-home-hero__arrow--prev",
            },
            breakpoints: {
                680: {
                    slidesPerView: 2,
                },
                1280: {
                    loop: false,
                    slidesPerView: 3,
                },
            },
        });
    });
}
