"use strict";
import Swiper from "swiper";
import { Navigation } from "swiper/modules";

export default function () {
    document.addEventListener("DOMContentLoaded", () => {
        const initSlider = document.querySelector(".o-home-specialties__grid ");
        if (!initSlider) return;

        const swiper = new Swiper(".o-home-specialties__grid ", {
            modules: [Navigation],
            slidesPerView: 1,
            spaceBetween: 26,
            autoHeight: true,
            loop: true,
            navigation: {
                nextEl: ".o-home-specialties__arrow--next",
                prevEl: ".o-home-specialties__arrow--prev",
            },
            breakpoints: {
                680: {
                    slidesPerView: 2,
                },
                1280: {
                    slidesPerView: 5,
                },
            },
        });
    });
}
