export default function neuroArchiveFilter() {
    const root = document.querySelector("[data-neuro-archive]");
    if (!root) return;

    const buttons = [...root.querySelectorAll("[data-neuro-filter]")];
    const cards = [...root.querySelectorAll("[data-neuro-cat]")];

    if (!buttons.length || !cards.length) return;

    const setActive = (key) => {
        buttons.forEach((btn) => {
            const isActive = btn.dataset.neuroFilter === key;
            btn.setAttribute("aria-pressed", isActive ? "true" : "false");

            // mantém teu padrão de botão (verde ativo / outline inativo)
            btn.classList.toggle("button__green", isActive);
            btn.classList.toggle("button__outline", !isActive);
        });

        cards.forEach((card) => {
            const cat = (card.dataset.neuroCat || "").toLowerCase();
            card.style.display = cat === key ? "" : "none";
        });
    };

    buttons.forEach((btn) => {
        btn.addEventListener("click", () => setActive(btn.dataset.neuroFilter));
    });
}
