"use strict";
import Swiper from "swiper";
import { Navigation } from "swiper/modules";

export default function () {
    document.addEventListener("DOMContentLoaded", () => {
        const initSlider = document.querySelector(
            ".o-home-testimonials__list "
        );
        if (!initSlider) return;

        const swiper = new Swiper(".o-home-testimonials__list ", {
            modules: [Navigation],
            slidesPerView: 1,
            spaceBetween: 26,
            autoHeight: true,
            loop: true,
            navigation: {
                nextEl: ".o-home-testimonials__arrow--next",
                prevEl: ".o-home-testimonials__arrow--prev",
            },
        });
    });
}
